class OAuthClient {
    constructor(clientId, redirectUri, scopes) {
        this.clientId = clientId;
        this.redirectUri = redirectUri;
        this.scopes = scopes;
    }

    async authenticate() {
        const authUrl = new URL('https://example.com/oauth/authorize');
        authUrl.searchParams.set('response_type', 'code');
        authUrl.searchParams.set('client_id', this.clientId);
        authUrl.searchParams.set('redirect_uri', this.redirectUri);
        authUrl.searchParams.set('scope', this.scopes.join(' '));
        window.location.href = authUrl.toString();
    }

    async handleRedirect() {
        const urlParams = new URLSearchParams(window.location.search);
        const code = urlParams.get('code');
        if (code) {
            const tokens = await this.exchangeCodeForTokens(code);
            localStorage.setItem('accessToken', tokens.access_token);
            localStorage.setItem('refreshToken', tokens.refresh_token);
            localStorage.setItem('expiresAt', Date.now() + tokens.expires_in * 1000);
        }
    }

    async exchangeCodeForTokens(code) {
        const response = await fetch('https://example.com/oauth/token', {
            method: 'POST',
            headers: {
                'Content-Type': 'application/x-www-form-urlencoded'
            },
            body: new URLSearchParams({
                grant_type: 'authorization_code',
                code: code,
                redirect_uri: this.redirectUri,
                client_id: this.clientId
            })
        });
        return await response.json();
    }

    async refreshToken() {
        const refreshToken = localStorage.getItem('refreshToken');
        if (!refreshToken) {
            throw new Error('Refresh token not available');
        }
        const response = await fetch('https://example.com/oauth/token', {
            method: 'POST',
            headers: {
                'Content-Type': 'application/x-www-form-urlencoded'
            },
            body: new URLSearchParams({
                grant_type: 'refresh_token',
                refresh_token: refreshToken,
                client_id: this.clientId
            })
        });
        const tokens = await response.json();
        localStorage.setItem('accessToken', tokens.access_token);
        localStorage.setItem('expiresAt', Date.now() + tokens.expires_in * 1000);
    }

    async getAccessToken() {
        const expiresAt = localStorage.getItem('expiresAt');
        if (!expiresAt || Date.now() >= expiresAt) {
            await this.refreshToken();
        }
        return localStorage.getItem('accessToken');
    }
}

